import { Hono } from 'hono'
const app = new Hono().basePath('/nobis')

// This handles the main React page
app.get('/', async (c) => {
  return c.env.ASSETS.fetch(c.req.raw)
})

// Example API route
app.get('/api/data', (c) => {
  return c.json({ status: "API is live" })
})

export default app